     1→//! Live CRM service backed by the SQLite store.
     2→//!
     3→//! [`LiveCrmService`] implements [`moltis_service_traits::CrmService`] by
     4→//! delegating to [`moltis_crm::SqliteCrmStore`].  Each RPC method deserialises
     5→//! its `serde_json::Value` params, calls the appropriate store operation, and
     6→//! serialises the result back.
     7→//!
     8→//! PII fields (email, phone) are exposed in responses — callers reach this
     9→//! service only through the auth-gated WebSocket layer.
    10→
    11→use std::sync::Arc;
    12→
    13→use {
    14→    async_trait::async_trait,
    15→    moltis_crm::{
    16→        Contact, ContactChannel, Interaction, Matter, SqliteCrmStore,
    17→        store::CrmStore,
    18→        types::{ContactStage, InteractionKind, MatterPhase, MatterStatus, PracticeArea},
    19→    },
    20→    moltis_service_traits::{CrmService, ServiceError, ServiceResult},
    21→    secrecy::{ExposeSecret, Secret},
    22→    serde_json::Value,
    23→};
    24→
    25→/// Live CRM service backed by a SQLite store.
    26→pub struct LiveCrmService {
    27→    store: Arc<SqliteCrmStore>,
    28→}
    29→
    30→impl LiveCrmService {
    31→    #[must_use]
    32→    pub fn new(store: Arc<SqliteCrmStore>) -> Self {
    33→        Self { store }
    34→    }
    35→}
    36→
    37→// ── Serialisation helpers ─────────────────────────────────────────────────────
    38→
    39→fn contact_to_json(c: Contact) -> Value {
    40→    serde_json::json!({
    41→        "id":         c.id,
    42→        "name":       c.name,
    43→        "source":     c.source,
    44→        "externalId": c.external_id,
    45→        "email":      c.email.as_ref().map(|s| s.expose_secret()),
    46→        "phone":      c.phone.as_ref().map(|s| s.expose_secret()),
    47→        "stage":      c.stage.as_str(),
    48→        "metadata":   c.metadata,
    49→        "createdAt":  c.created_at,
    50→        "updatedAt":  c.updated_at,
    51→    })
    52→}
    53→
    54→fn channel_to_json(ch: ContactChannel) -> Value {
    55→    serde_json::json!({
    56→        "id":          ch.id,
    57→        "contactId":   ch.contact_id,
    58→        "channelType": ch.channel_type,
    59→        "channelId":   ch.channel_id,
    60→        "displayName": ch.display_name,
    61→        "verified":    ch.verified,
    62→        "createdAt":   ch.created_at,
    63→        "updatedAt":   ch.updated_at,
    64→    })
    65→}
    66→
    67→fn matter_to_json(m: Matter) -> Value {
    68→    serde_json::json!({
    69→        "id":           m.id,
    70→        "contactId":    m.contact_id,
    71→        "title":        m.title,
    72→        "description":  m.description,
    73→        "status":       m.status.as_str(),
    74→        "phase":        m.phase.as_str(),
    75→        "practiceArea": m.practice_area.as_str(),
    76→        "createdAt":    m.created_at,
    77→        "updatedAt":    m.updated_at,
    78→    })
    79→}
    80→
    81→fn interaction_to_json(i: Interaction) -> Value {
    82→    serde_json::json!({
    83→        "id":        i.id,
    84→        "contactId": i.contact_id,
    85→        "matterId":  i.matter_id,
    86→        "kind":      i.kind.as_str(),
    87→        "summary":   i.summary,
    88→        "channel":   i.channel,
    89→        "createdAt": i.created_at,
    90→        "updatedAt": i.updated_at,
    91→    })
    92→}
    93→
    94→fn store_err(e: moltis_crm::Error) -> ServiceError {
    95→    ServiceError::message(e.to_string())
    96→}
    97→
    98→// ── CrmService impl ───────────────────────────────────────────────────────────
    99→
   100→#[async_trait]
   101→impl CrmService for LiveCrmService {
   102→    // ── Contacts ──────────────────────────────────────────────────────────────
   103→
   104→    async fn list_contacts(&self) -> ServiceResult {
   105→        let contacts = self.store.list().await.map_err(store_err)?;
   106→        Ok(Value::Array(
   107→            contacts.into_iter().map(contact_to_json).collect(),
   108→        ))
   109→    }
   110→
   111→    async fn get_contact(&self, params: Value) -> ServiceResult {
   112→        let id = require_str(&params, "id")?;
   113→        let contact = self.store.get(id).await.map_err(store_err)?;
   114→        Ok(contact.map(contact_to_json).unwrap_or(Value::Null))
   115→    }
   116→
   117→    async fn upsert_contact(&self, params: Value) -> ServiceResult {
   118→        let contact = parse_contact(params)?;
   119→        self.store.upsert(contact).await.map_err(store_err)?;
   120→        Ok(serde_json::json!({ "ok": true }))
   121→    }
   122→
   123→    async fn delete_contact(&self, params: Value) -> ServiceResult {
   124→        let id = require_str(&params, "id")?;
   125→        self.store.delete(id).await.map_err(store_err)?;
   126→        Ok(serde_json::json!({ "ok": true }))
   127→    }
   128→
   129→    // ── Contact channels ──────────────────────────────────────────────────────
   130→
   131→    async fn list_channels(&self, params: Value) -> ServiceResult {
   132→        let contact_id = require_str(&params, "contactId")?;
   133→        let channels = self
   134→            .store
   135→            .list_channels_for_contact(contact_id)
   136→            .await
   137→            .map_err(store_err)?;
   138→        Ok(Value::Array(
   139→            channels.into_iter().map(channel_to_json).collect(),
   140→        ))
   141→    }
   142→
   143→    async fn upsert_channel(&self, params: Value) -> ServiceResult {
   144→        let channel = parse_channel(params)?;
   145→        self.store
   146→            .upsert_channel(channel)
   147→            .await
   148→            .map_err(store_err)?;
   149→        Ok(serde_json::json!({ "ok": true }))
   150→    }
   151→
   152→    async fn delete_channel(&self, params: Value) -> ServiceResult {
   153→        let id = require_str(&params, "id")?;
   154→        self.store.delete_channel(id).await.map_err(store_err)?;
   155→        Ok(serde_json::json!({ "ok": true }))
   156→    }
   157→
   158→    // ── Matters ───────────────────────────────────────────────────────────────
   159→
   160→    async fn list_matters(&self, params: Value) -> ServiceResult {
   161→        let has_filters = params.is_object() && params.as_object().is_some_and(|o| !o.is_empty());
   162→        let matters = if has_filters {
   163→            let contact_id = params
   164→                .get("contactId")
   165→                .and_then(|v| v.as_str())
   166→                .map(ToOwned::to_owned);
   167→            let status = params
   168→                .get("status")
   169→                .and_then(|v| v.as_str())
   170→                .map(|s| s.parse::<MatterStatus>().map_err(ServiceError::message))
   171→                .transpose()?;
   172→            let phase = params
   173→                .get("phase")
   174→                .and_then(|v| v.as_str())
   175→                .map(|s| s.parse::<MatterPhase>().map_err(ServiceError::message))
   176→                .transpose()?;
   177→            let practice_area = params
   178→                .get("practiceArea")
   179→                .and_then(|v| v.as_str())
   180→                .map(|s| s.parse::<PracticeArea>().map_err(ServiceError::message))
   181→                .transpose()?;
   182→            let search = params
   183→                .get("search")
   184→                .and_then(|v| v.as_str())
   185→                .filter(|s| !s.is_empty())
   186→                .map(ToOwned::to_owned);
   187→            let offset = params.get("offset").and_then(|v| v.as_u64()).unwrap_or(0);
   188→            let limit = params.get("limit").and_then(|v| v.as_u64()).unwrap_or(50);
   189→            self.store
   190→                .list_matters_filtered(
   191→                    contact_id.as_deref(),
   192→                    status,
   193→                    phase,
   194→                    practice_area,
   195→                    search.as_deref(),
   196→                    offset,
   197→                    limit,
   198→                )
   199→                .await
   200→                .map_err(store_err)?
   201→        } else {
   202→            self.store.list_matters().await.map_err(store_err)?
   203→        };
   204→        Ok(Value::Array(
   205→            matters.into_iter().map(matter_to_json).collect(),
   206→        ))
   207→    }
   208→
   209→    async fn get_matter(&self, params: Value) -> ServiceResult {
   210→        let id = require_str(&params, "id")?;
   211→        let matter = self.store.get_matter(id).await.map_err(store_err)?;
   212→        Ok(matter.map(matter_to_json).unwrap_or(Value::Null))
   213→    }
   214→
   215→    async fn upsert_matter(&self, params: Value) -> ServiceResult {
   216→        let matter = parse_matter(params)?;
   217→        self.store.upsert_matter(matter).await.map_err(store_err)?;
   218→        Ok(serde_json::json!({ "ok": true }))
   219→    }
   220→
   221→    async fn delete_matter(&self, params: Value) -> ServiceResult {
   222→        let id = require_str(&params, "id")?;
   223→        self.store.delete_matter(id).await.map_err(store_err)?;
   224→        Ok(serde_json::json!({ "ok": true }))
   225→    }
   226→
   227→    // ── Interactions ──────────────────────────────────────────────────────────
   228→
   229→    async fn list_interactions(&self, params: Value) -> ServiceResult {
   230→        if let Some(contact_id) = params.get("contactId").and_then(|v| v.as_str()) {
   231→            let items = self
   232→                .store
   233→                .list_interactions_by_contact(contact_id)
   234→                .await
   235→                .map_err(store_err)?;
   236→            return Ok(Value::Array(
   237→                items.into_iter().map(interaction_to_json).collect(),
   238→            ));
   239→        }
   240→        if let Some(matter_id) = params.get("matterId").and_then(|v| v.as_str()) {
   241→            let items = self
   242→                .store
   243→                .list_interactions_by_matter(matter_id)
   244→                .await
   245→                .map_err(store_err)?;
   246→            return Ok(Value::Array(
   247→                items.into_iter().map(interaction_to_json).collect(),
   248→            ));
   249→        }
   250→        Err(ServiceError::message(
   251→            "list_interactions requires contactId or matterId",
   252→        ))
   253→    }
   254→
   255→    async fn get_interaction(&self, params: Value) -> ServiceResult {
   256→        let id = require_str(&params, "id")?;
   257→        let item = self.store.get_interaction(id).await.map_err(store_err)?;
   258→        Ok(item.map(interaction_to_json).unwrap_or(Value::Null))
   259→    }
   260→
   261→    async fn upsert_interaction(&self, params: Value) -> ServiceResult {
   262→        let interaction = parse_interaction(params)?;
   263→        self.store
   264→            .upsert_interaction(interaction)
   265→            .await
   266→            .map_err(store_err)?;
   267→        Ok(serde_json::json!({ "ok": true }))
   268→    }
   269→
   270→    async fn delete_interaction(&self, params: Value) -> ServiceResult {
   271→        let id = require_str(&params, "id")?;
   272→        self.store.delete_interaction(id).await.map_err(store_err)?;
   273→        Ok(serde_json::json!({ "ok": true }))
   274→    }
   275→}
   276→
   277→// ── Parse helpers ─────────────────────────────────────────────────────────────
   278→
   279→fn require_str<'a>(params: &'a Value, field: &'static str) -> Result<&'a str, ServiceError> {
   280→    params
   281→        .get(field)
   282→        .and_then(|v| v.as_str())
   283→        .ok_or_else(|| ServiceError::message(format!("missing field: {field}")))
   284→}
   285→
   286→fn parse_contact(p: Value) -> Result<Contact, ServiceError> {
   287→    let id = require_str(&p, "id")?.to_owned();
   288→    let name = require_str(&p, "name")?.to_owned();
   289→    let stage = p
   290→        .get("stage")
   291→        .and_then(|v| v.as_str())
   292→        .unwrap_or("lead")
   293→        .parse::<ContactStage>()
   294→        .map_err(ServiceError::message)?;
   295→    let now = now_ms();
   296→    Ok(Contact {
   297→        id,
   298→        name,
   299→        source: p
   300→            .get("source")
   301→            .and_then(|v| v.as_str())
   302→            .map(ToOwned::to_owned),
   303→        external_id: p
   304→            .get("externalId")
   305→            .and_then(|v| v.as_str())
   306→            .map(ToOwned::to_owned),
   307→        email: p
   308→            .get("email")
   309→            .and_then(|v| v.as_str())
   310→            .map(|s| Secret::new(s.to_owned())),
   311→        phone: p
   312→            .get("phone")
   313→            .and_then(|v| v.as_str())
   314→            .map(|s| Secret::new(s.to_owned())),
   315→        stage,
   316→        metadata: p
   317→            .get("metadata")
   318→            .cloned()
   319→            .unwrap_or_else(|| serde_json::json!({})),
   320→        created_at: p.get("createdAt").and_then(|v| v.as_u64()).unwrap_or(now),
   321→        updated_at: now,
   322→    })
   323→}
   324→
   325→fn parse_channel(p: Value) -> Result<ContactChannel, ServiceError> {
   326→    let id = require_str(&p, "id")?.to_owned();
   327→    let contact_id = require_str(&p, "contactId")?.to_owned();
   328→    let channel_type = require_str(&p, "channelType")?.to_owned();
   329→    let channel_id = require_str(&p, "channelId")?.to_owned();
   330→    let now = now_ms();
   331→    Ok(ContactChannel {
   332→        id,
   333→        contact_id,
   334→        channel_type,
   335→        channel_id,
   336→        display_name: p
   337→            .get("displayName")
   338→            .and_then(|v| v.as_str())
   339→            .map(ToOwned::to_owned),
   340→        verified: p.get("verified").and_then(|v| v.as_bool()).unwrap_or(false),
   341→        created_at: p.get("createdAt").and_then(|v| v.as_u64()).unwrap_or(now),
   342→        updated_at: now,
   343→    })
   344→}
   345→
   346→fn parse_matter(p: Value) -> Result<Matter, ServiceError> {
   347→    let id = require_str(&p, "id")?.to_owned();
   348→    let title = require_str(&p, "title")?.to_owned();
   349→    let status = p
   350→        .get("status")
   351→        .and_then(|v| v.as_str())
   352→        .unwrap_or("open")
   353→        .parse::<MatterStatus>()
   354→        .map_err(ServiceError::message)?;
   355→    let phase = p
   356→        .get("phase")
   357→        .and_then(|v| v.as_str())
   358→        .unwrap_or("intake")
   359→        .parse::<MatterPhase>()
   360→        .map_err(ServiceError::message)?;
   361→    let practice_area = p
   362→        .get("practiceArea")
   363→        .and_then(|v| v.as_str())
   364→        .unwrap_or("other")
   365→        .parse::<PracticeArea>()
   366→        .map_err(ServiceError::message)?;
   367→    let now = now_ms();
   368→    Ok(Matter {
   369→        id,
   370→        contact_id: p
   371→            .get("contactId")
   372→            .and_then(|v| v.as_str())
   373→            .map(ToOwned::to_owned),
   374→        title,
   375→        description: p
   376→            .get("description")
   377→            .and_then(|v| v.as_str())
   378→            .map(ToOwned::to_owned),
   379→        status,
   380→        phase,
   381→        practice_area,
   382→        created_at: p.get("createdAt").and_then(|v| v.as_u64()).unwrap_or(now),
   383→        updated_at: now,
   384→    })
   385→}
   386→
   387→fn parse_interaction(p: Value) -> Result<Interaction, ServiceError> {
   388→    let id = require_str(&p, "id")?.to_owned();
   389→    let contact_id = require_str(&p, "contactId")?.to_owned();
   390→    let kind = require_str(&p, "kind")?
   391→        .parse::<InteractionKind>()
   392→        .map_err(ServiceError::message)?;
   393→    let summary = require_str(&p, "summary")?.to_owned();
   394→    let now = now_ms();
   395→    Ok(Interaction {
   396→        id,
   397→        contact_id,
   398→        matter_id: p
   399→            .get("matterId")
   400→            .and_then(|v| v.as_str())
   401→            .map(ToOwned::to_owned),
   402→        kind,
   403→        summary,
   404→        channel: p
   405→            .get("channel")
   406→            .and_then(|v| v.as_str())
   407→            .map(ToOwned::to_owned),
   408→        created_at: p.get("createdAt").and_then(|v| v.as_u64()).unwrap_or(now),
   409→        updated_at: now,
   410→    })
   411→}
   412→
   413→fn now_ms() -> u64 {
   414→    use std::time::{SystemTime, UNIX_EPOCH};
   415→    SystemTime::now()
   416→        .duration_since(UNIX_EPOCH)
   417→        .unwrap_or_default()
   418→        .as_millis() as u64
   419→}
   420→
   421→// ── Tests ─────────────────────────────────────────────────────────────────────
   422→
   423→#[cfg(test)]
   424→#[allow(clippy::unwrap_used, clippy::expect_used)]
   425→mod tests {
   426→    use {super::*, sqlx::SqlitePool};
   427→
   428→    async fn make_service() -> LiveCrmService {
   429→        let pool = SqlitePool::connect("sqlite::memory:").await.unwrap();
   430→        moltis_crm::run_migrations(&pool).await.unwrap();
   431→        LiveCrmService::new(Arc::new(SqliteCrmStore::new(pool)))
   432→    }
   433→
   434→    // ── Contact CRUD ──────────────────────────────────────────────────────────
   435→
   436→    #[tokio::test]
   437→    async fn list_contacts_empty() {
   438→        let svc = make_service().await;
   439→        let result = svc.list_contacts().await.unwrap();
   440→        assert_eq!(result, serde_json::json!([]));
   441→    }
   442→
   443→    #[tokio::test]
   444→    async fn upsert_and_get_contact() {
   445→        let svc = make_service().await;
   446→        let id = uuid::Uuid::new_v4().to_string();
   447→        svc.upsert_contact(serde_json::json!({
   448→            "id": id,
   449→            "name": "Alice",
   450→            "stage": "lead",
   451→        }))
