        .await
        .unwrap();
        let mid = uuid::Uuid::new_v4().to_string();
        svc.upsert_matter(serde_json::json!({
            "id": mid,
            "contactId": contact_id,
            "title": "Contract Review",
            "status": "open",
            "phase": "intake",
