   200→        out.sort_by_key(|i| std::cmp::Reverse(i.updated_at));
   201→        Ok(out)
   202→    }
   203→
   204→    async fn list_interactions_by_matter(&self, matter_id: &str) -> Result<Vec<Interaction>> {
   205→        let interactions = self.interactions.read().unwrap_or_else(|e| e.into_inner());
   206→        let mut out: Vec<Interaction> = interactions
